    "slug": "dirty-signals-bot-traffic-junk-leads",
    "title": "Bot Traffic and Bad Lookalikes: How Dirty Signals Can Wreck Your Funnel and Your Targeting",
    "seoTitle": "Bot Traffic and Bad Lookalikes: How Dirty Signals Can Wreck Your Funnel and Your Targeting | Found Search Marketing",
    "excerpt": "When marketing reports CPL is down, but sales indicates that the leads are unusable, this could be a clear sign that your conversion stream is contaminated.",
    "publishedAt": "2026-03-20",
    "publishedLabel": "March 20, 2026",
    "authorName": "Maria Escobedo",
    "authorTitle": "Associate Data Analyst",
    "authorUrl": "https://foundsm.com/insights/authors/maria/",
    "heroImage": "https://foundsm.com/found2025/wp-content/uploads/2026/03/bot-traffic-sm.webp",
